const router = require('express').Router();
const Alert = require('../models/Alert');
const auth = require('../middleware/auth');

router.get('/', auth, async (req, res) => {
  try {
    const { type, status } = req.query;
    let query = {};
    if (type) query.type = type;
    if (status) query.status = status;
    const alerts = await Alert.find(query).limit(50);

    // Sort: PENDING first → REVIEW → RESOLVED, newest first within each group
    const priority = { PENDING: 0, REVIEW: 1, RESOLVED: 2 };
    alerts.sort((a, b) => {
      const pd = priority[a.status] - priority[b.status];
      if (pd !== 0) return pd;
      return new Date(b.createdAt) - new Date(a.createdAt);
    });

    res.json(alerts);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

router.patch('/:id/resolve', auth, async (req, res) => {
  try {
    const alert = await Alert.findByIdAndUpdate(req.params.id, { status: 'RESOLVED' }, { new: true });
    res.json(alert);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

router.delete('/:id', auth, async (req, res) => {
  try {
    await Alert.findByIdAndDelete(req.params.id);
    res.json({ message: 'Alert deleted' });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

module.exports = router;
